ytearray() # 存储原始接收数据使用 bytearray 格式，转换成字节数组的类型，方便16进制的显示与发送 self.whole_send_text = bytearray() self.time_stamp_time = 1000 #时间输入的定时 self.timing_send_time = 1000 #定时发送的定时 self.current_ports = [] #存储窗口选择界面的串口列表 # 使用队列处理图形数据 self.graph_data_queue = queue.Queue() self.t_list = [] self.x_list = [] self.y_list = [] self.max_data_points = 100 # 最大数据点数 # 新增数据接收缓冲区 self.data_buffer = &#34;&#34; # 用于累积数据 self.buffer_max_size = 2048 # 缓冲区最大大小 # 新增数据解析统计 self.data_points_received = 0 self.data_points_parsed = 0 # 初始化用到的定时器 def Init_all_timers(self): # 设置定时器用于定期检查串口变化，看串口增加或减少了，都可以通过这个定时器的任务函数进行实现 self.timer_of_change_serial = QTimer() self.timer_of_change_serial.timeout.connect(self.check_serial_ports) self.timer_of_change_serial.start(1000) # 每1秒检查一次 #接受任务的定时器 self.timer_of_receive = QTimer() self.timer_of_receive.timeout.connect(self.receive_serial_data_task) self.timer_of_receive.start(10) #每10ms进行一次判断，然后接收 #自动保存的定时器，勾选自动保存之后，每过一秒进行一个保存、刷新 self.timer_of_auto_save = QTimer() self.timer_of_auto_save.timeout.connect(self.timer_of_auto_save_task) self.timer_of_auto_save.start(1000) #时间戳与定时器发送相关的定时器 self.timer_of_time_stamp = QTimer() self.timer_of_time_stamp.timeout.connect(self.time_stamp_time_task) self.timer_of_timing_send = QTimer() self.timer_of_timing_send.timeout.connect(self.Send_Period_Time_Task) #当前时间的显示 self.timer_of_time_refresh = QTimer() self.timer_of_time_refresh.timeout.connect(self.time_refresh_show) self.timer_of_time_refresh.start(1000) # 每1秒检查一次 # 添加图形更新定时器 self.timer_of_graph_refresh = QTimer() self.timer_of_graph_refresh.timeout.connect(self.graph_refresh_show) self.timer_of_graph_refresh.start(50) # 每50ms更新一次图表 # 新增缓冲区处理定时器 self.timer_of_buffer_process = QTimer() self.timer_of_buffer_process.timeout.connect(self.process_data_buffer) self.timer_of_buffer_process.start(50) # 每50ms处理一次缓冲区 # 初始化连接所有信号与槽函数 def Init_all_functions(self): self.ui.Clear_Receive_Button.clicked.connect(self.Clear_Receive_Button_Task) self.ui.Save_Window_Button.clicked.connect(self.Save_Window_Button_Task) self.ui.Serial_Operate_Button.toggled.connect(self.Serial_Operate_Button_Task) self.ui.Serial_Choose.currentIndexChanged.connect(self.Serial_Choose_Task) #窗口选择类型控件连接到我们相应的槽函数 self.ui.Baud_Rate.currentIndexChanged.connect(self.Baud_Rate_Task) self.ui.Data_Bit.currentIndexChanged.connect(self.Data_Bit_Task) self.ui.Stop_Bit.currentIndexChanged.connect(self.Stop_Bit_Task) self.ui.Check_Bit.currentIndexChanged.connect(self.Check_Bit_Task) self.ui.Hex_Show.toggled.connect(self.Hex_Show_Task) self.ui.DTR.toggled.connect(self.DTR_Task) self.ui.RTS.toggled.connect(self.RTS_Task) self.ui.Auto_Save.toggled.connect(self.Auto_Save_Task) self.ui.Time_Stamp.toggled.connect(self.Time_Stamp_Task) self.ui.Send_Button.clicked.connect(self.Send_Button_Task) self.ui.Clear_Send_Button.clicked.connect(self.Clear_Send_Button_Task) self.ui.R_num.setText(f&#39;R: {len(self.receive_raw_data)}&#39;) self.ui.S_num.setText(f&#39;S: {len(self.whole_send_text)}&#39;) self.ui.Time_Stamp_Time.textChanged.connect(self.Change_Time_Stamp_Task) self.ui.Send_Period_Time.textChanged.connect(self.Send_Period_Time_Change_Task) self.ui.Send_New_Line.toggled.connect(self.Send_New_Line_Task) self.ui.Time_Send.toggled.connect(self.Time_Send_Task) self.ui.Hex_Send.toggled.connect(self.Hex_Send_Task) self.ui.Clear_Graph.clicked.connect(self.Clear_Graph_Task) self.ui.Save_Graph.clicked.connect(self.Save_Graph_Task) self.ui.line_type.currentIndexChanged.connect(self.Line_Type_Change_Task) # self.ui.Show_Dot_Num.textChanged.connect(self.Show_Dot_Num_Task) # 初始化串口相关配置 def Init_serial_settings(self): self.ser = Serial() #声明一个串口变量 self.ser.close() #而后将窗口关闭，等待后续配置 # 初始化串口列表 self.update_serial_ports() #此函数用于初始化更新窗口列表 # 串口选择槽函数 def Serial_Choose_Task(self): self.ser.close() if self.ui.Serial_Operate_Button.isChecked() == True: #True开启串口，false关闭串口 self.ser = Serial(self.ui.Serial_Choose.currentText(), self.ui.Baud_Rate.currentText(), timeout=1) #读取选择的COM及其波特率读取下来，赋值到ser变量 self.ser.open() else: self.ser.close() # 波特率选择槽函数 def Baud_Rate_Task(self): self.ser.close() if self.ui.Serial_Operate_Button.isChecked() == True: self.ser = Serial(self.ui.Serial_Choose.currentText(), self.ui.Baud_Rate.currentText(), timeout=1) self.ser.open() else: self.ser.close() # 停止位选择槽函数 def Stop_Bit_Task(self): stop_bits_map = { &#39;1&#39;: STOPBITS_ONE, &#39;1.5&#39;: STOPBITS_ONE_POINT_FIVE, &#39;2&#39;: STOPBITS_TWO } stop_bits = self.ui.Stop_Bit.currentText() if stop_bits in stop_bits_map: self.ser.stopbits = stop_bits_map[stop_bits] if self.ser.is_open: try: # 需要重新打开串口才能应用新的停止位设置 self.ser.close() self.ser.open() except SerialException as e: QMessageBox.warning(self.ui, &#34;串口错误&#34;, f&#34;无法重新打开串口: {str(e)}&#34;) self.ui.Serial_Operate_Button.setChecked(False) # 数据位选择槽函数 def Data_Bit_Task(self): self.ser.bytesize = int(self.ui.Data_Bit.currentText()) # 校验位选择槽函数 def Check_Bit_Task(self): if (self.ui.Check_Bit.currentText() == &#39;None&#39;): self.ser.parity = &#39;N&#39; elif (self.ui.Check_Bit.currentText() == &#39;Odd&#39;): self.ser.parity = &#39;O&#39; elif (self.ui.Check_Bit.currentText() == &#39;Even&#39;): self.ser.parity = &#39;E&#39; else: self.ser.parity = &#39;N&#39; # 串口操作槽函数 def Serial_Operate_Button_Task(self): if self.ui.Serial_Operate_Button.isChecked() == True: self.ser = Serial(self.ui.Serial_Choose.currentText(), self.ui.Baud_Rate.currentText(), timeout=1) self.ser.open() else: self.ser.close() # 保存窗口槽函数 def Save_Window_Button_Task(self): # 检查是否有内容可保存 if not self.receive_raw_data: QMessageBox.information(self.ui, &#34;提示&#34;, &#34;接收窗口没有数据可保存&#34;) return # 弹出文件选择对话框 file_path, _ = QFileDialog.getSaveFileName( #使用QFileDialog，此函数返回两个参数，第二个不需要，使用 _ 取出接收，第一个file_path为保存路径 self.ui, &#34;保存接收数据&#34;, f&#34;serial_data_{datetime.now().strftime(&#39;%Y%m%d_%H%M%S&#39;)}.txt&#34;, &#34;文本文件 (*.txt)&#34; ) # 如果用户选择了文件路径 if file_path: try: # 获取接收窗口的文本内容 content = self.ui.receive_text.toPlainText() #当前接手界面一段话，存储到content数组里 # 写入文件 with open(file_path, &#39;w&#39;, encoding=&#39;utf-8&#39;) as f: f.write(content) #使用文件操作显示写到file_path路径txt文件里 # 显示成功消息 QMessageBox.information(self.ui, &#34;成功&#34;, f&#34;数据已成功保存到:
{file_path}&#34;) except Exception as e: # 显示错误消息 QMessageBox.critical(self.ui, &#34;错误&#34;, f&#34;保存文件时发生错误:
{str(e)}&#34;) # 清除接收槽函数 def Clear_Receive_Button_Task(self): self.ui.receive_text.clear() self.receive_raw_data.clear() self.ui.R_num.setText(f&#39;R: {len(self.receive_raw_data)}&#39;) # 16进制显示槽函数 def Hex_Show_Task(self): if self.ui.Hex_Show.isChecked() == True: self.is_hex_receive = True else: self.is_hex_receive = False self.update_receive_display() # DTR选择槽函数 def DTR_Task(self): if self.ser.is_open: try: # 设置DTR信号状态 self.ser.dtr = self.ui.DTR.isChecked() except SerialException as e: QMessageBox.warning(self.ui, &#34;串口错误&#34;, f&#34;设置DTR信号时发生错误: {str(e)}&#34;) else: self.ui.DTR.setChecked(False) # RTS选择槽函数 def RTS_Task(self): if self.ser.is_open: try: # 设置RTS信号状态 self.ser.rts = self.ui.RTS.isChecked() except SerialException as e: QMessageBox.warning(self.ui, &#34;串口错误&#34;, f&#34;设置RTS信号时发生错误: {str(e)}&#34;) else: self.ui.RTS.setChecked(False) # 自动选择槽函数 def Auto_Save_Task(self): if self.ui.Auto_Save.isChecked(): # 启用自动保存，第一次文件创建做准备 if not hasattr(self, &#39;auto_save_file&#39;): # 如果还没有设置保存文件，弹出文件选择对话框 file_path, _ = QFileDialog.getSaveFileName( self.ui, &#34;选择自动保存文件&#34;, f&#34;serial_auto_save_{datetime.now().strftime(&#39;%Y%m%d_%H%M%S&#39;)}.txt&#34;, &#34;文本文件 (*.txt)&#34; ) if file_path: self.auto_save_file = file_path # 立即保存当前接收到的所有数据 QMessageBox.warning(self.ui, &#34;提示&#34;, &#34;已开启自动保存！&#34;) if hasattr(self, &#39;receive_raw_data&#39;): with open(self.auto_save_file, &#39;wb&#39;) as f: f.write(self.receive_raw_data) else: if hasattr(self, &#39;receive_raw_data&#39;): with open(self.auto_save_file, &#39;wb&#39;) as f: f.write(self.receive_raw_data) else: pass return # 自动保存定时任务 def timer_of_auto_save_task(self): if hasattr(self, &#39;auto_save_file&#39;): #每个时间段进行判断，自动实现保存任务 self.Auto_Save_Task() # 修改时间戳周期的函数 def Change_Time_Stamp_Task(self): if self.is_time_stamp: if self.ui.Time_Stamp_Time.displayText(): self.time_stamp_time = int(self.ui.Time_Stamp_Time.displayText()) else: self.time_stamp_time = 1000 self.timer_of_time_stamp.stop() self.timer_of_time_stamp.setInterval(self.time_stamp_time) self.timer_of_time_stamp.start() else: pass # 时间戳定时任务 def time_stamp_time_task(self): if self.is_time_stamp: if self.is_hex_receive: self.receive_raw_data += (&#39;
&#39; + f&#34;{datetime.now().strftime(&#39;时间戳：[%Y-%m-%d %H:%M:%S]&#39;)}&#34; + &#39;
&#39;) else: self.receive_raw_data += ( &#39;
&#39; + f&#34;{datetime.now().strftime(&#39;时间戳：[%Y-%m-%d %H:%M:%S]&#39;)}&#34; + &#39;
&#39;).encode(&#39;utf-8&#39;, errors=&#39;replace&#39;) # 开启时间戳槽函数 def Time_Stamp_Task(self): if self.ui.Time_Stamp.isChecked() == True: self.is_time_stamp = True else: self.is_time_stamp = False self.Change_Time_Stamp_Task() # 清楚发送槽函数 def Clear_Send_Button_Task(self): self.ser.write(self.ui.SendText.clear()) # self.whole_send_text.clear() # 发送槽函数 def Send_Button_Task(self): hex_send_text = &#39;&#39; if self.is_hex_send: #16进制发送 for i, byte in enumerate(self.ui.SendText.toPlainText().encode()): #16进制发送，byte数组类型，对于读取文本文件需要进行编码SendText，编成bytearray类型 # 每两个字节添加一个空格 if i &gt; 0: #对每个字节进行判断 hex_send_text += &#34; &#34; #加空格，每每一个字节之间有一个空格 if i &gt; 0 and i % 27 == 0: hex_send_text += &#34;
&#34; #选择发送多少字节之后进行换行 hex_send_text += f&#34;{byte:02X}&#34; hex_send_text += &#39; &#39; if self.is_send_newline: #发送新行的判断 hex_send_text += &#39;
&#39; #发送新行，在最后加一个换行符 self.ser.write(hex_send_text.encode()) #同时在串口发送时也进行编码，编码成字节类型进行发送 else: #如果是正常文本发送 if self.is_send_newline: self.ser.write((self.ui.SendText.toPlainText() + &#39;
&#39;).encode()) #先进行编码 else: self.ser.write(self.ui.SendText.toPlainText().encode()) self.whole_send_text += self.ui.SendText.toPlainText().encode() self.ui.S_num.setText(&#39;S:&#39; + str(len(self.whole_send_text))) #将发送的文本都存到whole_send_text，这样保存发送数据的时候可以调用whole_send_text字符串 # 修改定时发送周期的函数 def Send_Period_Time_Change_Task(self): #发送部分的计数，实时显示发送多少字节 if self.is_timing_send: if self.ui.Send_Period_Time.displayText(): self.timing_send_time = int(self.ui.Send_Period_Time.displayText()) else: self.timing_send_time = 1000 self.timer_of_timing_send.stop() self.timer_of_timing_send.setInterval(self.timing_send_time) self.timer_of_timing_send.start() else: pass # 开启定时发送的函数 def Send_Period_Time_Task(self): if self.is_timing_send: self.Send_Button_Task() # 定时发送槽函数 def Time_Send_Task(self): if self.ui.Time_Send.isChecked() == True: self.is_timing_send = True else: self.is_timing_send = False self.Send_Period_Time_Change_Task() # 更新下方时间显示 def time_refresh_show(self): self.ui.Current_time.setText( f&#39;当前时间: {datetime.now().hour:02d}:&#39; f&#39;{datetime.now().minute:02d}:{datetime.now().second:02d}&#39;) # 16进制发送槽函数 def Hex_Send_Task(self): if self.ui.Hex_Send.isChecked(): self.is_hex_send = True else: self.is_hex_send = False # 发送新行槽函数 def Send_New_Line_Task(self): if self.ui.Send_New_Line.isChecked(): self.is_send_newline = True else: self.is_send_newline = False # 检查串口列表是否有变化,以及定时，每一秒检查一次 def check_serial_ports(self): ports = comports() new_ports = [port.device for port in ports] # 如果串口列表有变化，更新UI if set(new_ports) != set(self.current_ports): #用set将当前串口变成集合，每一秒对比前面串口集合，变化就调用更新串口函数 self.update_serial_ports() # 更新串口列表 def update_serial_ports(self): # 获取当前选择的串口（如果有COM） current_selection = self.ui.Serial_Choose.currentText() if self.ui.Serial_Choose.count() &gt; 0 else &#34;&#34; # 清空当前列表 self.ui.Serial_Choose.clear() self.ui.Serial_Choose.addItem(&#34;请选择串口...&#34;) # 获取可用串口 ports = comports() #通过comports函数获取可用的COM口 self.current_ports = [port.device for port in ports] #将每个串口取出